UPDATE posts
SET status = 'DELETED',
    deleted_at = NOW()
WHERE id = #{id}
  AND user_id = #{userId}
  AND status != 'DELETED'

UPDATE posts
SET status = 'REJECTED',
    moderation_reason = #{moderationReason}
WHERE id = #{id}
  AND status != 'DELETED'

UPDATE posts
SET status = 'HIDDEN',
    moderation_reason = #{moderationReason}
WHERE id = #{id}
  AND status = 'PUBLISHED'
